import React, {type Ref, useMemo, useRef, useState} from 'react';
import './styles.scss'
import {Box} from "../../_compat";
import {Header, Navigation} from "../../_compat";
import {type RouteObject, useRoutes} from "react-router-dom";
import {checkPermissions, mapSectionsToRoutes} from "../Navigation/helper";
import {useMediaQuery} from "react-responsive";
import type {IHeaderRef} from "../Header";
import {useLanguage, useScrollState} from "../../hooks";
import {usePermissions} from "../../contexts/PermissionsContext";
import {breakpoints, type IMenuItem} from "@lmb-it/kitsconcerto-types";
import {useKitsTheme} from "../../_compat";

interface ILTRProps {
    routes: IMenuItem[];
    headerRef: Ref<IHeaderRef | null>;
}

const Routes = ({routes}: { routes: RouteObject[] }) => {
    return useRoutes(routes);
}

const AdminLayout = ({routes, headerRef}:ILTRProps) => {

    const mainRef = useRef<HTMLDivElement>(null);

    const isSmallDevice = useMediaQuery({maxWidth: breakpoints.lg})

    const {scrollState} = useScrollState({
        target:mainRef.current
    })
    const isScrolledUp = scrollState.y >= 25

    const [visible, setVisible] = useState(false)

    const {check} = usePermissions()
    const {t, currentLanguage} = useLanguage()
    const {colorMode} = useKitsTheme()
    const layoutThemeClass = colorMode === 'dark' ? 'layout-dark' : 'layout-light'
    const permittedRoutes = checkPermissions(routes, check)
    const filteredRoutes = mapSectionsToRoutes(permittedRoutes)

    const routeComponent = useMemo(() => {

        return <Routes routes={filteredRoutes}/>

    }, [])
    return (
        <Box ref={mainRef} className={`layout-container ${layoutThemeClass} layout-colorscheme-menu layout-static p-ripple-disabled`} id={'admin-layout'}>
            <Box
                className={'layout-sidebar'}>
                <Navigation
                    setVisible={setVisible}
                    visible={isSmallDevice && visible}
                    placement={currentLanguage === 'ar' ? 'rtl' : 'ltr'}
                    routes={permittedRoutes}
                />
            </Box>

            <Box
                className={'layout-content-wrapper'}
            >
                <Box id={'layout-topbar'}
                     className={'layout-topbar transition-all animation-linear transition-duration-200 '+(isScrolledUp?'sticky-bar':'')}
                     position={'sticky'} top={0}>
                    <Header hide={visible} setHide={setVisible} ref={headerRef} routes={filteredRoutes}/>
                </Box>
                <Box className={'layout-content'} overflow={'auto'}>
                    {/*<Box h={'full'} w={'full'}>*/}
                    {routeComponent}
                    {/*</Box>*/}
                </Box>
            </Box>
        </Box>
    );

};

export default AdminLayout;
